import React from 'react';
import { createPortal } from 'react-dom';
import { placeBelowOrAbove } from '../shared/positioningUtils';

const VIEWPORT_MARGIN = 12;
const PANEL_GAP = 8;
const UI_FONT_STACK = 'var(--tf-sans)';

// Visibility gate. When a parent provides `false`, the icon is hidden entirely.
// Default `true` keeps existing usage outside the gated subtree unchanged.
export const InfoHintVisibilityContext = React.createContext<boolean>(true);

const InfoHint: React.FC<{ text: string; compact?: boolean }> = ({ text, compact = false }) => {
  const visible = React.useContext(InfoHintVisibilityContext);
  const buttonRef = React.useRef<HTMLButtonElement | null>(null);
  const panelRef = React.useRef<HTMLDivElement | null>(null);
  const [open, setOpen] = React.useState(false);
  const [position, setPosition] = React.useState<{ top: number; left: number; width: number } | null>(null);
  const tooltipId = React.useId();

  const updatePosition = React.useCallback(() => {
    if (typeof window === 'undefined' || !buttonRef.current) {
      return;
    }

    const buttonRect = buttonRef.current.getBoundingClientRect();
    const width = compact ? 228 : 260;
    const panelHeight = panelRef.current?.offsetHeight ?? 0;
    const { top, left } = placeBelowOrAbove(buttonRect, width, panelHeight, {
      gap: PANEL_GAP,
      edgeMargin: VIEWPORT_MARGIN,
      align: compact ? 'left' : 'right',
    });
    setPosition({ top, left, width });
  }, [compact]);

  React.useLayoutEffect(() => {
    if (!open) {
      return;
    }

    updatePosition();
    const handleViewportChange = () => updatePosition();
    window.addEventListener('resize', handleViewportChange);
    window.addEventListener('scroll', handleViewportChange, true);
    return () => {
      window.removeEventListener('resize', handleViewportChange);
      window.removeEventListener('scroll', handleViewportChange, true);
    };
  }, [open, updatePosition]);

  // Early return AFTER all hooks so the hook-call order is stable across
  // visibility toggles (Rules of Hooks). Hiding the icon entirely when the
  // form-level "Explain inputs" toggle is off.
  if (!visible) return null;

  return (
    <>
      <span style={wrapStyle}>
        <button
          ref={buttonRef}
          type="button"
          aria-label="Variable information"
          aria-describedby={open ? tooltipId : undefined}
          aria-expanded={open}
          onMouseEnter={() => setOpen(true)}
          onMouseLeave={() => setOpen(false)}
          onFocus={() => setOpen(true)}
          onBlur={() => setOpen(false)}
          style={compact ? compactButtonStyle : buttonStyle}
        >
          i
        </button>
      </span>
      {open && typeof document !== 'undefined'
        ? createPortal(
            <div
              id={tooltipId}
              ref={panelRef}
              role="tooltip"
              style={{
                ...panelStyle,
                width: position?.width ?? (compact ? 228 : 260),
                top: position?.top ?? 0,
                left: position?.left ?? VIEWPORT_MARGIN,
              }}
            >
              {text}
            </div>,
            document.body
          )
        : null}
    </>
  );
};

const wrapStyle: React.CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  flexShrink: 0,
};

const buttonStyle: React.CSSProperties = {
  width: 16,
  height: 16,
  borderRadius: '50%',
  border: '1px solid var(--tf-border-strong)',
  background: 'var(--tf-bg-elevated)',
  color: 'var(--tf-amber)',
  fontSize: "var(--tf-fs-micro)",
  fontWeight: 700,
  lineHeight: 1,
  cursor: 'pointer',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  padding: 0,
};

const compactButtonStyle: React.CSSProperties = {
  ...buttonStyle,
  width: 14,
  height: 14,
  fontSize: "var(--tf-fs-micro)",
};

const panelStyle: React.CSSProperties = {
  position: 'fixed',
  zIndex: 1200,
  border: '1px solid var(--tf-border)',
  borderRadius: 'var(--tf-radius)',
  padding: '10px 12px',
  background: 'var(--tf-bg-elevated)',
  color: 'var(--tf-text)',
  fontSize: "var(--tf-fs-base)",
  fontFamily: UI_FONT_STACK,
  lineHeight: 1.55,
  pointerEvents: 'none',
};

export default InfoHint;
